    $maxPrice = $request->input('max_price');
    $sortBy = $request->input('sort_by', 'relevance');
    $perPage = $request->input('per_page', 20);

    $sql = "SELECT p.*, c.name as category_name,
            CASE 
                WHEN p.name LIKE ? THEN 3
                WHEN p.name LIKE ? THEN 2
                WHEN p.description LIKE ? THEN 1
                ELSE 0
            END as relevance_score
            FROM products p
            LEFT JOIN categories c ON p.category_id = c.id
            WHERE p.status = 'active'";

    $bindings = [];

    if ($query) {
        $exactMatch = $query;
        $startsWith = $query . '%';
        $contains = '%' . $query . '%';
        
        $bindings[] = $exactMatch;
        $bindings[] = $startsWith;
        $bindings[] = $contains;
        
        $sql .= " AND (p.name LIKE ? OR p.description LIKE ? OR p.sku LIKE ?)";
        $bindings[] = $contains;
        $bindings[] = $contains;
        $bindings[] = $contains;
    } else {
        $bindings[] = '';
        $bindings[] = '';
        $bindings[] = '';
    }

    if ($category) {
        $sql .= " AND p.category_id = ?";
        $bindings[] = $category;
    }

    if ($minPrice !== null && $minPrice !== '') {
        $sql .= " AND p.price >= ?";
        $bindings[] = $minPrice;
    }

    if ($maxPrice !== null && $maxPrice !== '') {
        $sql .= " AND p.price <= ?";
        $bindings[] = $maxPrice;
    }

    switch ($sortBy) {
        case 'price_asc':
            $sql .= " ORDER BY p.price ASC";
            break;
        case 'price_desc':
            $sql .= " ORDER BY p.price DESC";
            break;
        case 'name':
            $sql .= " ORDER BY p.name ASC";
