        case 'newest':
            $sql .= " ORDER BY p.created_at DESC";
            break;
        case 'relevance':
        default:
            if ($query) {
                $sql .= " ORDER BY relevance_score DESC, p.name ASC";
            } else {
                $sql .= " ORDER BY p.created_at DESC";
            }
            break;
    }

    $countSql = "SELECT COUNT(*) as total FROM (" . $sql . ") as count_query";
    $totalCount = DB::select(DB::raw($countSql), $bindings)[0]->total;

